const row = $input.first().json;
const id = row['Spec ID'];
const l = row.Language;
const t = (l == 'he' ? row['Title HE'] : row['Title EN']);
const s = (l == 'he' ? row['Slug HE'] : row['Slug EN']);

return { id, language: l, title: t, slug: s, originalData: row };

const aiResponse = JSON.parse($input.first().json.output);
const payload = {
  title: aiResponse.title,
  slug: aiResponse.slug,
  status: 'draft',
  content: '<main>' + aiResponse.sections.map(s => s.html).join('') + '</main><script type="application/ld+json">' + JSON.stringify(aiResponse.schema) + '</script>',
  meta: {
    og_description: aiResponse.og.description
  },
  acf: {
    cta_label: aiResponse.cta.label,
    cta_href: aiResponse.cta.href
  }
};

return {
  payload,
  specId: aiResponse.id,
  language: $('Extract Spec Data').first().json.language
};

